import React from 'react';
import { Link, BrowserRouter, Routes, Route, Switch } from 'react-router-dom';
import About from './Components/Frame/About';
import Home from './Components/Frame/Home';
import Project from './Components/Frame/Project';
import Contact from './Components/Frame/Contact';

function Navbar() {
  return (
    <div>
      <nav>
        <ul className='header'>
          <li><Link to="/home">Home</Link></li>
          <li><Link to="/about">About</Link></li>
          <li><Link to="/project">Project</Link></li>
          <li><Link to="/contact">Contact</Link></li>
        </ul>
      </nav>
    </div>
  );
}

function App() {
  return (
    <BrowserRouter>
      <Navbar />
      <Switch>
        <Route path="/" element={<Home />} />
        <Route path="/about" element={<About />} />
        <Route path="/project" element={<Project />} />
        <Route path="/contact" element={<Contact />} />
      </Switch>
    </BrowserRouter>
  );
}

export default App;
